// Format the function output into Slack-ready and log-ready payloads.
const result = $input.first().json;

const total_alerts = (result.alerts_created || 0) + (result.alerts_escalated || 0);
const has_activity = total_alerts > 0 || (result.alerts_cured || 0) > 0;

// Severity classifier for Slack icon
let severity_icon = '✅';
if ((result.level_3_count || 0) > 0) severity_icon = '🚨';
else if ((result.level_2_count || 0) > 0) severity_icon = '⚠️';
else if ((result.level_1_count || 0) > 0) severity_icon = '📋';

return [{
  json: {
    // Summary fields
    alerts_created: result.alerts_created || 0,
    alerts_escalated: result.alerts_escalated || 0,
    alerts_cured: result.alerts_cured || 0,
    certs_scanned: result.certs_scanned || 0,
    level_1_count: result.level_1_count || 0,
    level_2_count: result.level_2_count || 0,
    level_3_count: result.level_3_count || 0,
    total_alerts: total_alerts,
    has_activity: has_activity,
    severity_icon: severity_icon,

    // Metadata
    run_timestamp: new Date().toISOString(),
    run_date: new Date().toISOString().split('T')[0],
    n8n_execution_id: $execution.id,
    n8n_workflow_id: $workflow.id
  }
}];
